import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote — base premiums", () => {
    it("returns 5G processing fee for an empty item list", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      });
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("computes base premium for a single sword (100G + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it.todo("computes base premium for a single amulet (60G + 5G fee)");
    it.todo("computes base premium for a single staff (80G + 5G fee)");
    it.todo("computes base premium for a single potion (40G + 5G fee)");
    it.todo("computes base premium for a single component (25G + 5G fee)");
    it.todo("computes base premium for multiple items (sword + amulet = 160G + 5G fee)");
  });

  describe("Quote — component block pricing", () => {
    it.todo("prices 2 runes at 50G (no block)");
    it.todo("prices 3 alike runes at 60G (block of 3)");
    it.todo("prices 4 runes at 100G (no block — block requires exactly 3)");
    it.todo("prices 3 runes + 3 moonstones at 120G (two separate blocks)");
    it.todo("does not apply block for 2 runes + 1 moonstone (different types)");
  });

  describe("Quote — item-level modifiers", () => {
    it.todo("adds 50% cursed surcharge to the cursed item only");
    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
    it.todo("applies both cursed and high-enchantment surcharges to the same item");
    it.todo("does not apply high-enchantment surcharge for enchantment 4");
    it.todo("item-level modifiers apply only to the affected item in a multi-item policy");
  });

  describe("Quote — policy-level modifiers", () => {
    it.todo("adds 10% first-insurance surcharge on the policy base premium");
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up discount on second and subsequent quotes");
    it.todo("applies all policy-level modifiers together (loyalty + first insurance + follow-up)");
  });

  describe("Quote — rounding", () => {
    it.todo("rounds premium up (ceil) in MHPCO's favor");
  });

  describe("Quote — integration", () => {
    it.todo("newcomer with cursed sword: 165G");
    it.todo("long-standing customer second contract with cursed high-enchantment sword: 160G");
  });

  describe("Quote — errors", () => {
    it.todo("throws error for unknown item type");
  });

  describe("Claim — basic reimbursement", () => {
    it.todo("reimburses damage minus 100G deductible for a standard item");
    it.todo("reimburses damage to a component minus 100G deductible");
    it.todo("applies deductible per damaged item in a multi-item claim");
  });

  describe("Claim — enchantment and material clauses", () => {
    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
    it.todo("reimburses fully for dragon-material items, then deductible");
    it.todo("applies 50% rule when both dragon-material and enchantment >= 8");
    it.todo("dragon-material with enchantment < 8 gets full reimbursement minus deductible");
  });

  describe("Claim — cap", () => {
    it.todo("caps total payout at 2x insurance sum");
    it.todo("tracks remaining cap across successive claims");
    it.todo("cap is based on unmodified insurance values, not premiums");
  });

  describe("Claim — payout rounding", () => {
    it.todo("rounds payout down (floor) in MHPCO's favor");
  });

  describe("Claim — errors", () => {
    it.todo("throws error when damage references an item not in the policy");
    it.todo("throws error when more damages of a type than insured items");
    it.todo("throws error for negative damage amount");
  });
});

