const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);

function countByType(components: any[]): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const c of components) {
    counts[c.type] = (counts[c.type] ?? 0) + 1;
  }
  return counts;
}

function componentGroupPremium(count: number): number {
  return count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
}

function componentPremium(items: any[]): number {
  const components = items.filter(isComponent);
  const typeCounts = countByType(components);
  return Object.values(typeCounts).reduce(
    (sum, count) => sum + componentGroupPremium(count),
    0,
  );
}

function itemPremium(item: any): number {
  const base = BASE_PREMIUMS[item.type] ?? 0;
  let surcharge = 0;
  if (item.cursed) surcharge += base * 0.5;
  if (item.enchantment >= 5) surcharge += base * 0.3;
  return base + surcharge;
}

function policyBasePremium(items: any[]): number {
  const mainItems = items.filter((item: any) => !isComponent(item));
  const mainBase = mainItems.reduce(
    (sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] ?? 0),
    0,
  );
  return mainBase + componentPremium(items);
}

function calculateQuotePremium(items: any[]): number {
  const mainItems = items.filter((item: any) => !isComponent(item));
  const mainTotal = mainItems.reduce(
    (sum: number, item: any) => sum + itemPremium(item),
    0,
  );
  const componentTotal = componentPremium(items);
  const policyBase = policyBasePremium(items);
  const firstInsurance = policyBase * 0.1;
  return Math.ceil(mainTotal + componentTotal + firstInsurance + PROCESSING_FEE);
}

export function processScenario(scenario: any): { results: { premium: number }[] } {
  const results = scenario.steps.map((step: any) => {
    const premium = calculateQuotePremium(step.items);
    return { premium };
  });
  return { results };
}

