function calculateQuotePremium(items: any[], customer: any): number {
  const mainItems = items.filter((item: any) => !isComponent(item));
  const mainBase = mainItems.reduce(
    (sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] ?? 0),
    0,
  );
  const mainSurcharges = mainItems.reduce(
    (sum: number, item: any) => sum + itemSurcharge(item),
    0,
  );
  const componentTotal = componentPremium(items);
  const policyBase = mainBase + componentTotal;
  const firstInsurance = policyBase * 0.1;
  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
  return Math.ceil(policyBase + mainSurcharges + firstInsurance - loyaltyDiscount + PROCESSING_FEE);
}

export function processScenario(scenario: any): { results: { premium: number }[] } {
  const results = scenario.steps.map((step: any) => {
    const premium = calculateQuotePremium(step.items, scenario.customer);
    return { premium };
  });
  return { results };
}

